def test_admin_creates_training_course_valid_payload(admin_token, api_client, audit_record_exists):
    payload = {
        "title": "Workplace Safety 101",
        "description": "Core safety training",
        "duration_minutes": 60,
        "is_mandatory": True
    }
    resp = api_client.post(
        "/api/training-courses",
        json=payload,
        headers={"Authorization": f"Bearer {admin_token}"}
    )
    assert resp.status_code in (200, 201)
    body = resp.json()
    assert "id" in body and body["id"]
    assert audit_record_exists(entity_id=body["id"], action="CREATE", entity_type="training-course")

def test_create_training_course_missing_mandatory_title_returns_400(admin_token, api_client):
    payload = {
        "description": "No title provided",
        "duration_minutes": 30,
        "is_mandatory": False
    }
    resp = api_client.post(
        "/api/training-courses",
        json=payload,
        headers={"Authorization": f"Bearer {admin_token}"}
    )
    assert resp.status_code == 400
    body = resp.json()
    errors = str(body).lower()
    assert "title" in errors

def test_create_training_course_title_exceeds_max_boundary_returns_400(admin_token, api_client):
    over_max_title = "A" * 256
    payload = {
        "title": over_max_title,
        "description": "BVA over-boundary test",
        "duration_minutes": 45,
        "is_mandatory": False
    }
    resp = api_client.post(
        "/api/training-courses",
        json=payload,
        headers={"Authorization": f"Bearer {admin_token}"}
    )
    assert resp.status_code == 400
    body = resp.json()
    assert "title" in str(body).lower()

def test_create_training_course_unauthenticated_returns_401(api_client):
    payload = {
        "title": "Unauth Course Attempt",
        "description": "Should be rejected",
        "duration_minutes": 30,
        "is_mandatory": False
    }
    resp = api_client.post("/api/training-courses", json=payload)
    assert resp.status_code == 401

def test_create_training_course_non_admin_role_returns_403(employee_token, api_client):
    payload = {
        "title": "Forbidden Course Attempt",
        "description": "Employee should not create courses",
        "duration_minutes": 30,
        "is_mandatory": False
    }
    resp = api_client.post(
        "/api/training-courses",
        json=payload,
        headers={"Authorization": f"Bearer {employee_token}"}
    )
    assert resp.status_code == 403
